VALUES
  ('optician-moex-00129', 'optician', 'optician-moex-114-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '驗配隱形眼鏡進行評估時，若鏡片配適太鬆，改善配適的方法，下列何者正確？', '["選擇較平之基弧（BC），鏡片直徑（OAD）不變", "減少鏡片直徑，基弧不變", "鏡片直徑不變，選擇較陡基弧", "基弧變大，鏡片直徑縮小"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:26+00:00", "source_pdf_sha1": "b70d36ef6657", "answer_pdf_sha1": "5101fd87d88e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00130', 'optician', 'optician-moex-114-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '在球面軟式隱形眼鏡配適評估，若遇配適過緊，可採用下列那種做法以取得理想配適？', '["將鏡片BOZR變陡，並同時減少TD", "將鏡片BOZR變陡，並同時增加TD", "將鏡片BOZR變平，並同時增加TD", "將鏡片BOZR變平，並同時減少TD"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:26+00:00", "source_pdf_sha1": "b70d36ef6657", "answer_pdf_sha1": "5101fd87d88e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00131', 'optician', 'optician-moex-114-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '劉先生的眼鏡處方為-4.25DS/-1.50DC×090，他想驗配一副沒有散光的軟式隱形眼鏡，其處方最接近下列何者？', '["-4.00DS", "-5.00DS", "-6.00DS", "-7.00DS"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:26+00:00", "source_pdf_sha1": "b70d36ef6657", "answer_pdf_sha1": "5101fd87d88e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00132', 'optician', 'optician-moex-114-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '驗配軟式隱形眼鏡，有關鏡片直徑和鏡片基弧與角膜的關係，下列何者正確？', '["只要測出角膜曲率（keratometry），就可以選出合適的隱形眼鏡鏡片，讓患者有完美的配戴經驗", "非球面的鏡片設計，不會影響到驗配成功率", "角膜直徑變化對角膜矢狀高度（sagittalheight）的影響大於角膜曲率的變化", "對眼瞼裂高（palpebralaperture）的評估，軟式隱形眼鏡相對硬式更為重要"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:26+00:00", "source_pdf_sha1": "b70d36ef6657", "answer_pdf_sha1": "5101fd87d88e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00133', 'optician', 'optician-moex-114-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關驗配硬式透氧隱形眼鏡（RGP）的敘述，下列何者正確？', '["角膜e值（偏心率，eccentrity）越大，配適時通常選擇直徑（TD）較小的鏡片", "眼瞼張力（眼皮鬆緊度）越鬆，隱形眼鏡鏡片要選擇較大的直徑", "遠視隱形眼鏡片的中心較厚，重心會往後移；近視鏡片的中心較薄，重心會往前移", "當配戴的隱形眼鏡基弧屈光度大於角膜的平屈光度時，會產生負度數淚液鏡效果"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:26+00:00", "source_pdf_sha1": "b70d36ef6657", "answer_pdf_sha1": "5101fd87d88e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00134', 'optician', 'optician-moex-114-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '下列何者可判斷配戴軟式隱形眼鏡為太緊？', '["鏡片過度偏心，眨眼滑動大於1mm", "眨眼後模糊，過一陣子才有清楚的視覺", "鏡片位置在角膜中間，並在角膜輪部外緣有約1mm的寬度", "最初感覺到舒適，但在持續配戴數小時感到疼痛不舒服"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:26+00:00", "source_pdf_sha1": "b70d36ef6657", "answer_pdf_sha1": "5101fd87d88e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00135', 'optician', 'optician-moex-114-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '某隱形眼鏡患者配戴日拋型隱形眼鏡。主訴：「有時候剛戴上一眼或兩眼的鏡片會有點不舒服，並且隨著 時間的推移會變得更嚴重。」最可能的原因為何？', '["對消毒水過敏", "隱形眼鏡前後戴反了", "戴錯眼了", "角膜破皮"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:26+00:00", "source_pdf_sha1": "b70d36ef6657", "answer_pdf_sha1": "5101fd87d88e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00136', 'optician', 'optician-moex-114-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '角膜上緣弧形病灶（superiorepithelialarcuatelesions,SEALs）為戴隱形眼鏡者在角膜上緣近輪部處產生一 弧形的表皮破損，下列敘述何者錯誤？', '["和微生物感染有關", "和鏡片的機械性摩擦有關", "停止配戴鏡片後會症狀消失", "改用不同鏡片或不同弧度可能解決症狀"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:26+00:00", "source_pdf_sha1": "b70d36ef6657", "answer_pdf_sha1": "5101fd87d88e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00137', 'optician', 'optician-moex-114-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '依據EfronContactLensPractice教課書，有關配戴隱形眼鏡所造成的角膜水腫（oedema），下列敘述何者錯誤？', '["白天正常配戴水膠隱形眼鏡（hydrogellenses）使用，可能會使眼睛產生1～6%的角膜水腫", "晚上配戴水膠隱形眼鏡過夜睡覺，隔天可能會使眼睛產生5～13%的角膜水腫", "晚上配戴矽水膠（siliconehydrogellenses）過夜睡覺，隔天可能會使眼睛產生少於4%的角膜水腫", "沒有配戴任何隱形眼鏡過夜睡覺，隔天可能會使眼睛產生5%的角膜水腫"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:26+00:00", "source_pdf_sha1": "b70d36ef6657", "answer_pdf_sha1": "5101fd87d88e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00138', 'optician', 'optician-moex-114-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '下列何種鏡片狀況較易誘發3點和9點破皮染色（3and9o’clockstaining）？', '["鏡片太薄", "鏡片向上偏位", "鏡片向下偏位", "非球面鏡片"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:26+00:00", "source_pdf_sha1": "b70d36ef6657", "answer_pdf_sha1": "5101fd87d88e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
